function formatId(id: string | number): string {
  if (typeof id === "string") {
    return id.toUpperCase();
  }
  return id.toFixed(0);
}

console.log(formatId("user-42"));
console.log(formatId(7.9));

function double(n: number | null): number {
  if (n) {
    return n * 2;
  }
  return 0;
}

console.log(double(0));

